import{_ as a,o as i,c as e,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：PLL 频率限幅与锁定检测","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：PLL 频率限幅与锁定检测","tags":["power-electronics"],"status":"learning","summary":"锁相环（phase-locked loop / PLL）不能只输出一个估算角度就结束。工程固件通常还要做频率限幅（frequency limit）和锁定检测（lock detection）："},"headers":[],"relativePath":"content/power/concepts/control/single-phase-pll-lock-detector.md","filePath":"content/power/concepts/control/single-phase-pll-lock-detector.md","lastUpdated":null}'),n={name:"content/power/concepts/control/single-phase-pll-lock-detector.md"};function t(p,s,o,h,r,c){return i(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="概念-pll-频率限幅与锁定检测" tabindex="-1">概念：PLL 频率限幅与锁定检测 <a class="header-anchor" href="#概念-pll-频率限幅与锁定检测" aria-label="Permalink to &quot;概念：PLL 频率限幅与锁定检测&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>锁相环（phase-locked loop / PLL）不能只输出一个估算角度就结束。工程固件通常还要做频率限幅（frequency limit）和锁定检测（lock detection）：</p><ul><li>频率限幅：把估算频率限制在合理范围，例如 45 Hz 到 55 Hz。</li><li>锁定检测：只有相位误差和频率误差连续一段时间满足条件，才认为 PLL 已锁定。</li><li>解锁判断：相位突变、频率限幅、输入异常时，撤销锁定状态。</li></ul><p>本节只讲一个概念：PLL 输出既是控制量，也是状态机和保护逻辑的输入。</p><p>保密边界：不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）会把 PLL 状态用于功率因数校正、旁路（bypass）同步、逆变器同步和模式切换。如果 PLL 因噪声或电网异常输出不可信角度，后续控制不能盲目使用。</p><p>频率限幅和锁定检测可以把“算法还在算”与“结果可信”区分开。保护逻辑和故障锁存（fault latch）通常要根据这些状态决定是否允许并网、旁路切换或继续闭环控制。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>PLL 像一个追踪电网的指针。频率限幅相当于给指针转速加机械限位：再着急也不能转到不合理速度。锁定检测相当于观察指针是否稳定贴住目标一段时间，而不是刚好经过目标就宣布成功。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f_raw = f_nom + PI(vq)</span></span>
<span class="line"><span>f_est = clamp(f_raw, f_min, f_max)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>phase_ok = abs(theta_err) &lt; phase_band</span></span>
<span class="line"><span>freq_ok = abs(f_est - f_grid_est) &lt; freq_band</span></span>
<span class="line"><span>limit_ok = not frequency_limited</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if phase_ok and freq_ok and limit_ok for hold_time:</span></span>
<span class="line"><span>    locked = true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if abs(theta_err) &gt; unlock_phase or frequency_limited:</span></span>
<span class="line"><span>    locked = false</span></span></code></pre></div><p>这里的 <code>f_grid_est</code> 在真实工程里可能来自 PLL 内部估算、过零测频或独立电网检测模块。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pll_lock_detector.py</span></span></code></pre></div><p>观察：</p><ul><li>电网频率从 50 Hz 跳到 54 Hz 后，<code>f_raw</code> 可能越过限幅边界，但 <code>f_est</code> 被夹在 45 Hz 到 55 Hz 内。</li><li>锁定状态必须在相位误差和频率误差持续满足条件后才拉高。</li><li>120 ms 的相位跳变会让锁定状态掉下去。</li><li>频率限幅标志可以作为保护或状态机判断的输入。</li></ul><p>一个仿真任务：改变相位跳变幅度，观察锁定状态是否掉下去，以及相位误差什么时候重新进入锁定范围。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pll_lock_detector.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jump</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deg </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pll_lock_jump_15.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pll_lock_detector.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jump</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deg </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">45</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pll_lock_jump_45.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件实现通常会拆成几层：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PLL update</span></span>
<span class="line"><span>  -&gt; raw frequency</span></span>
<span class="line"><span>  -&gt; frequency clamp</span></span>
<span class="line"><span>  -&gt; phase accumulator</span></span>
<span class="line"><span>  -&gt; lock detector</span></span>
<span class="line"><span>  -&gt; mode/protection/state-machine decision</span></span></code></pre></div><p>工程上要注意：</p><ul><li>限幅值不能只按理想电网设定，还要考虑允许工作范围和保护策略。</li><li>锁定检测要有保持时间，避免单点噪声误判。</li><li>解锁条件要保守，尤其涉及旁路切换和并联系统同步时。</li><li>锁定状态不是故障锁存本身，但可能触发故障锁存或禁止某些模式。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：PLL 输出频率越接近 50 Hz 就一定可信。<br> 正确理解：还要看相位误差、是否限幅、是否持续稳定。</p></li><li><p>错误理解：限幅只是为了防止数值太大。<br> 正确理解：限幅也是保护边界，防止异常采样让角度飞掉。</p></li><li><p>错误理解：一进入锁定带就可以立刻认为锁定。<br> 正确理解：要持续满足条件一段时间，否则噪声会导致误锁。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 <code>f_raw</code> 和 <code>f_est</code> 的区别。</li><li>能解释为什么锁定检测需要保持时间。</li><li>能在图中指出频率限幅标志、锁定状态、相位误差和解锁点。</li><li>能说明 PLL lock 状态如何影响 UPS 模式切换和保护逻辑。</li><li>能基于 <code>single_phase_pll_lock_detector.py</code> 生成的仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 <code>f_raw</code> 越过 55 Hz 时，固件仍应使用限幅后的 <code>f_est</code>？</li><li>为什么不能只要相位误差小于 5 度就立刻宣布锁定？</li><li>PLL 解锁后，哪些 UPS 动作应该被禁止或延后？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pll_lock_detector.py</code> 看到 <code>f_raw</code> 会越过限幅，而 <code>f_est</code> 被限制在 45 Hz 到 55 Hz。公司平台 PLL 的频率限幅一般设在哪里？</li><li>图中 120 ms 相位跳变后锁定状态掉下去。实际代码里 PLL 解锁会触发故障锁存，还是只禁止旁路/并网动作？</li><li>锁定检测需要保持 15 ms。公司代码里的 PLL lock 判据通常要求连续多少个控制周期满足相位和频率条件？</li></ul>`,34)])])}const _=a(n,[["render",t]]);export{k as __pageData,_ as default};
